SELECT COUNT(DISTINCT user_id) AS unique_users_who_liked_or_commented
FROM (
    SELECT user_id FROM post_likes
    UNION
    SELECT author_id AS user_id FROM post_comments
);

SELECT 
    (SELECT COUNT(*) FROM post_likes WHERE post_id = 1) AS total_likes,
    (SELECT COUNT(*) FROM post_comments WHERE post_id = 1) AS total_comments;

SELECT COUNT(comment_id) AS total_comments_by_user
FROM post_comments
WHERE author_id = 1;

SELECT post_title
FROM posts
WHERE post_id = 1;

SELECT SUM(views) AS total_views
FROM post_statistics
WHERE post_id = 1;

SELECT views
FROM post_statistics
WHERE post_id = 1 AND time_interval = '20220629_040954';

SELECT SUM(views) AS total_views
FROM post_statistics
WHERE post_id = 1;
